    const interestRate = EPP_RATES[selectedBank]?.[selectedDuration] || 0;
    const deposit = finalSystemCost * 0.05;
    const loanPrincipal = finalSystemCost - deposit;
    const totalLoanRepayment = loanPrincipal * (1 + interestRate / 100);
    const installment = selectedDuration > 0 ? totalLoanRepayment / selectedDuration : 0;

    return (
        <div className="space-y-6">
