    const retailCharge = kWh > RETAIL_THRESHOLD ? RETAIL_CHARGE_AMOUNT : 0;
    const kwtbbBase = usageCost + capacityCost + networkCost;
    const kwtbbCost = kwtbbBase * KWTBB_RATE;
    let sstCost = 0;
    if (kWh > SST_THRESHOLD) {
        const taxableKWh = kWh - SST_THRESHOLD;
        const costPerUnit = effectiveUsageRate + CAPACITY_RATE + NETWORK_RATE + afaRate;
        const taxableVariableCost = taxableKWh * costPerUnit;
        const totalTaxableBase = taxableVariableCost + retailCharge;
        sstCost = Math.max(0, totalTaxableBase * SST_RATE);
    }
    const eeiRate = getEEIRate(kWh);
    const eeiCost = -(kWh * eeiRate);

    const totalBill = usageCost + capacityCost + networkCost + afaCost + retailCharge + kwtbbCost + sstCost + eeiCost;
    return { usageCost, capacityCost, networkCost, afaCost, retailCharge, kwtbbCost, sstCost, eeiCost, totalBill, unitRate: effectiveUsageRate };
};

export const calculateKWhFromBill = (targetBill: number, afaRate: number = 0): number => {
    if (!targetBill || targetBill <= 0) return 0;
    let low = 0, high = 100000, mid = 0, iterations = 0;
    while (high - low > 0.0001 && iterations < 100) {
        mid = (low + high) / 2;
        const res = calculateBill(mid, afaRate);
        if (res.totalBill < targetBill) low = mid;
        else high = mid;
        iterations++;
    }
    return mid;
};

export const computeSolarMetrics = (billAmount: number): SolarData => {
  const estimatedUsage = calculateKWhFromBill(billAmount);
  const monthlyKWhPerPanel = (PANEL_WATTAGE * PEAK_SUN_HOURS * 30) / 1000;

  // Basic sizing: cover at least 90% of usage or based on panel sizing steps
  const idealPanels = estimatedUsage > 0 ? Math.ceil(estimatedUsage / monthlyKWhPerPanel) : 0;
  const panelCount = Math.max(0, idealPanels);
  const solarGeneration = panelCount * monthlyKWhPerPanel;

  const morningUsage = estimatedUsage * MORNING_USAGE_PERCENT;
  const surplus = solarGeneration - morningUsage;

  const exportedToGrid = Math.max(0, surplus);
  const importedFromGrid = Math.max(0, estimatedUsage - morningUsage - Math.min(solarGeneration - morningUsage, 0)); // simplified import logic

  return {
    billAmount,
    estimatedUsage,
    solarGeneration,
    morningUsage,
    exportedToGrid,
    importedFromGrid: Math.max(0, estimatedUsage - Math.min(estimatedUsage, solarGeneration)), // Simplified for visualization
    systemSize: (panelCount * PANEL_WATTAGE) / 1000,
    panelCount
  };
};

