            />
          </foreignObject>
        </g>

        {/* Label B: Est Usage Box */}
        <g transform="translate(30, 160)">
          <rect width="210" height="70" rx="15" fill="#f8fafc" stroke="#3b82f6" strokeWidth="2" />
          <text x="20" y="25" className="text-[10px] font-black fill-slate-400 uppercase tracking-widest">B: Estimated Usage (B)</text>
          <text x="20" y="55" className="text-xl font-black fill-slate-800">{formatKWh(data.estimatedUsage)}</text>
        </g>

        {/* Label E & F: Grid Interaction */}
        <g transform="translate(700, 190)">
          {/* Fix: Removing invalid 'shadow' attribute on SVG rect element */}
          <rect width="280" height="140" rx="15" fill="white" stroke="#e2e8f0" strokeWidth="2" />
          <text x="20" y="30" className="text-[10px] font-black fill-slate-400 uppercase tracking-widest">Grid Interaction</text>

          <g transform="translate(0, 55)">
            <text x="20" y="0" className="text-[11px] font-black fill-green-600 uppercase">E: Export (C - D)</text>
            <text x="20" y="25" className="text-xl font-black fill-green-700">{formatKWh(data.exportedToGrid)}</text>
          </g>

          <g transform="translate(0, 105)">
            <text x="20" y="0" className="text-[11px] font-black fill-red-500 uppercase">F: Import (B - D)</text>
            <text x="20" y="25" className="text-xl font-black fill-red-600">{formatKWh(data.importedFromGrid)}</text>
          </g>
        </g>

        {/* Footer Status Panel */}
        <g transform="translate(30, 590)">
           <rect width="940" height="40" rx="8" fill="#1e293b" />
           <g transform="translate(30, 25)">
              <circle r="5" fill="#f97316" />
              <text x="15" y="4" className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Solar DC</text>
           </g>
           <g transform="translate(200, 25)">
              <circle r="5" fill="#3b82f6" />
              <text x="15" y="4" className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">AC Power</text>
           </g>
           <g transform="translate(450, 25)">
              <text x="15" y="4" textAnchor="middle" className="text-[10px] font-black fill-white uppercase tracking-[0.2em]">
                System Mode: {isExporting ? "NEM EXPORT MODE" : "GRID IMPORT MODE"}
              </text>
           </g>
        </g>
      </svg>
