        {/* 2. Solar AC Path: Inverter -> Junction */}
        <path d={`M580 ${acY} H ${junctionX}`} fill="none" stroke="#3b82f6" strokeWidth="6" />
        {isGenerating && <path d={`M580 ${acY} H ${junctionX}`} fill="none" stroke="white" strokeWidth="2" strokeDasharray="8 8" className="animate-flow" />}

