          </g>

          <g transform="translate(0, 105)">
            <text x="20" y="0" className="text-[11px] font-black fill-red-500 uppercase">F: Import (B-D)</text>
            <text x="20" y="25" className="text-xl font-black fill-red-600">{formatKWh(data.importedFromGrid)}</text>
          </g>
        </g>

        {/* Legend Bar (Fixed color and visibility) */}
        <g transform="translate(30, 590)">
           <rect width="940" height="40" rx="8" fill="#1e293b" />
           <g transform="translate(40, 25)">
              <circle r="6" fill="#f97316" />
              <text x="15" y="4" className="text-[10px] font-black uppercase tracking-widest" fill="white">DC Solar</text>
           </g>
           <g transform="translate(200, 25)">
              <circle r="6" fill="#3b82f6" />
              <text x="15" y="4" className="text-[10px] font-black uppercase tracking-widest" fill="white">AC Consumption</text>
           </g>
           <g transform="translate(400, 25)">
