        </g>

        <g transform="translate(30, 160)">
          <rect width="210" height="70" rx="15" fill="#f8fafc" stroke="#3b82f6" strokeWidth="2" />
          <text x="20" y="25" className="text-[10px] font-black fill-slate-400 uppercase tracking-widest">B: Est. Monthly Usage</text>
          <text x="20" y="55" className="text-xl font-black fill-slate-800">{formatKWh(data.estimatedUsage)}</text>
        </g>

        <g transform="translate(710, 180)">
          <rect width="250" height="140" rx="15" fill="white" stroke="#e2e8f0" strokeWidth="2" />
