    const usageInBlock = Math.min(remaining, block.limit);
    cost += usageInBlock * block.rate;
    remaining -= usageInBlock;
    if (remaining <= 0) break;
  }

  return cost;
};

/**
 * Standard TNB Bill calculation for domestic users
 */
export const calculateBill = (kWh: number, afaRate: number = 0): CalculationResult => {
    const usageCost = calculateTNBUsageCost(kWh);
    const afaCost = kWh * afaRate;

    // KWTBB is 1.6% applicable to consumers with consumption > 300 kWh
    const kwtbbCost = kWh > 300 ? usageCost * KWTBB_RATE : 0;

    // SST is 8% for usage > 600kWh on (Usage Cost + ICPT)
    let sstCost = 0;
    if (kWh > SST_THRESHOLD_KWH) {
        sstCost = (usageCost + afaCost) * SST_RATE;
    }

    const rawTotal = usageCost + afaCost + kwtbbCost + sstCost;
    const totalBill = Math.max(MINIMUM_MONTHLY_CHARGE, rawTotal);

    return { 
      usageCost, 
      capacityCost: 0, 
      networkCost: 0, 
      afaCost, 
      retailCharge: 0, 
      kwtbbCost, 
      sstCost, 
      eeiCost: 0, 
      totalBill, 
      unitRate: usageCost / (kWh || 1) 
    };
};

