    while (high - low > 0.01 && iterations < 100) {
        mid = (low + high) / 2;
        const res = calculateBill(mid, afaRate);
        if (res.totalBill < targetBill) low = mid;
        else high = mid;
        iterations++;
    }
    return mid;
};

export const computeSolarMetrics = (billAmount: number, afaRate: number = 0): SolarData => {
  const estimatedUsage = calculateKWhFromBill(billAmount, afaRate);
  const monthlyKWhPerPanel = (PANEL_WATTAGE * PEAK_SUN_HOURS * 30) / 1000;

  const panelCount = Math.max(0, Math.ceil(estimatedUsage / monthlyKWhPerPanel));
  const solarGeneration = panelCount * monthlyKWhPerPanel;

  // TNB NEM 3.0 Separation Logic:
  // Daytime Consumption (Ud), Nighttime Consumption (Un), Solar Generation (S)
  const Ud = estimatedUsage * MORNING_USAGE_PERCENT;
  const Un = estimatedUsage * (1 - MORNING_USAGE_PERCENT);
  const S = solarGeneration;

  // Grid Flows:
  // If Solar > Daytime usage, we export the excess.
  // If Solar < Daytime usage, we import the deficit.
  const exportedToGrid = Math.max(0, S - Ud);
  const importedFromGrid = Un + Math.max(0, Ud - S);

  /**
   * TNB NEM 3.0 ACCURATE BILLING:
   * 1. Energy Charge: Based on (Import - Export) credits.
   * 2. ICPT (AFA): Charged on GROSS IMPORT only.
   * 3. KWTBB: Based on Energy Charge of (Import - Export).
   */
  const netkWh = Math.max(0, importedFromGrid - exportedToGrid);

  const netEnergyCharge = calculateTNBUsageCost(netkWh);
  const grossAfaCost = importedFromGrid * afaRate;
  const kwtbbCost = netkWh > 300 ? netEnergyCharge * KWTBB_RATE : 0;

  let sstCost = 0;
  if (netkWh > SST_THRESHOLD_KWH) {
      sstCost = (netEnergyCharge + grossAfaCost) * SST_RATE;
  }

  const postSolarBill = Math.max(MINIMUM_MONTHLY_CHARGE, netEnergyCharge + grossAfaCost + kwtbbCost + sstCost);
  const totalSaving = Math.max(0, billAmount - postSolarBill);

  return {
    billAmount,
    afaRate,
    estimatedUsage,
    solarGeneration,
    morningUsage: Ud,
    exportedToGrid,
    importedFromGrid,
    systemSize: (panelCount * PANEL_WATTAGE) / 1000,
    panelCount,
    totalSaving
  };
};

