import { 
  TNB_BLOCKS, MINIMUM_MONTHLY_CHARGE, KWTBB_RATE, SST_THRESHOLD_KWH, 
  SST_RATE, PANEL_WATTAGE, PEAK_SUN_HOURS, MORNING_USAGE_PERCENT 
} from '../constants';
import { CalculationResult, SolarData } from '../types';

/**
 * Calculates base usage cost using TNB Tariff A stepped blocks
 */
export const calculateTNBUsageCost = (kWh: number): number => {
  let cost = 0;
  let remaining = Math.max(0, kWh);

  for (const block of TNB_BLOCKS) {
    const usageInBlock = Math.min(remaining, block.limit);
    cost += usageInBlock * block.rate;
    remaining -= usageInBlock;
    if (remaining <= 0) break;
  }

  return cost;
};

/**
 * Standard TNB Bill calculation for domestic users
 */
export const calculateBill = (kWh: number, afaRate: number = 0): CalculationResult => {
    const usageCost = calculateTNBUsageCost(kWh);
    const afaCost = kWh * afaRate;

    // KWTBB is 1.6% applicable to consumers with consumption > 300 kWh
    const kwtbbCost = kWh > 300 ? usageCost * KWTBB_RATE : 0;

    // SST is 8% for usage > 600kWh on (Usage Cost + ICPT)
    let sstCost = 0;
    if (kWh > SST_THRESHOLD_KWH) {
        sstCost = (usageCost + afaCost) * SST_RATE;
    }

    const rawTotal = usageCost + afaCost + kwtbbCost + sstCost;
    const totalBill = Math.max(MINIMUM_MONTHLY_CHARGE, rawTotal);

    return { 
      usageCost, 
      capacityCost: 0, 
      networkCost: 0, 
      afaCost, 
      retailCharge: 0, 
      kwtbbCost, 
      sstCost, 
      eeiCost: 0, 
      totalBill, 
      unitRate: usageCost / (kWh || 1) 
    };
};

export const calculateKWhFromBill = (targetBill: number, afaRate: number = 0): number => {
    if (!targetBill || targetBill <= MINIMUM_MONTHLY_CHARGE) return 0;
    let low = 0, high = 20000, mid = 0, iterations = 0;
    while (high - low > 0.01 && iterations < 100) {
        mid = (low + high) / 2;
        const res = calculateBill(mid, afaRate);
        if (res.totalBill < targetBill) low = mid;
        else high = mid;
        iterations++;
    }
    return mid;
};

export const computeSolarMetrics = (billAmount: number, afaRate: number = 0): SolarData => {
  const estimatedUsage = calculateKWhFromBill(billAmount, afaRate);
  const originalBillData = calculateBill(estimatedUsage, afaRate);

  const monthlyKWhPerPanel = (PANEL_WATTAGE * PEAK_SUN_HOURS * 30) / 1000;
  const panelCount = Math.max(0, Math.ceil(estimatedUsage / monthlyKWhPerPanel));
  const solarGeneration = panelCount * monthlyKWhPerPanel;

  // TNB NEM 3.0 Separation:
  const morningUsage = estimatedUsage * MORNING_USAGE_PERCENT;
  const exportedToGrid = Math.max(0, solarGeneration - morningUsage);
  const importedFromGrid = Math.max(0, estimatedUsage - morningUsage);

  /**
   * REFINED SAVING CALCULATION (Net Bill Analysis):
   * 1. Calculate the bill for energy still imported from the grid.
   * 2. Calculate the value of exported energy (at the current average tariff).
   * 3. Net Bill = (Import Bill) - (Export Value).
   * 4. Saving = Original Bill - Net Bill.
   */
  const importBillData = calculateBill(importedFromGrid, afaRate);
  const exportValue = exportedToGrid * originalBillData.unitRate;

  const netBill = importBillData.totalBill - exportValue;
  const totalSaving = Math.max(0, billAmount - netBill);

  return {
    billAmount,
    afaRate,
    estimatedUsage,
    solarGeneration,
    morningUsage,
    exportedToGrid,
    importedFromGrid,
    systemSize: (panelCount * PANEL_WATTAGE) / 1000,
    panelCount,
    totalSaving
  };
};

